int main() {
    int n;
    std::cin >> n;
    int a = n / 100;
    int b = (n / 10) % 10;
    int c = n % 10;
    if (a * a * a + b * b * b + c * c * c == n) {
        std::cout << "Yes" << std::endl;
    } else {
        std::cout << "No" << std::endl;
